     *
     * # Arguments
     *
     * * `mint_url` - URL of the Cashu mint to use (e.g., <https://mint.example.com>)
     *
     * # Errors
     *
     * Returns an error if the API request fails or authentication fails
     */
    suspend fun `setMintUrl`(`mintUrl`: kotlin.String): NpubCashUserResponse
    
    companion object
}

