        return PreparedMelt(UniffiWithHandle, value)
    }

    override fun read(buf: ByteBuffer): PreparedMelt {
        return lift(buf.getLong())
    }

    override fun allocationSize(value: PreparedMelt) = 8UL

    override fun write(value: PreparedMelt, buf: ByteBuffer) {
        buf.putLong(lower(value))
