/**
 * @suppress
 */
public object FfiConverterTypeWalletSqliteDatabase: FfiConverter<WalletSqliteDatabase, Long> {
    override fun lower(value: WalletSqliteDatabase): Long {
        return value.uniffiCloneHandle()
    }

    override fun lift(value: Long): WalletSqliteDatabase {
        return WalletSqliteDatabase(UniffiWithHandle, value)
    }

    override fun read(buf: ByteBuffer): WalletSqliteDatabase {
        return lift(buf.getLong())
    }

    override fun allocationSize(value: WalletSqliteDatabase) = 8UL

    override fun write(value: WalletSqliteDatabase, buf: ByteBuffer) {
        buf.putLong(lower(value))
    }
}



