/**
 * FFI Error type that wraps CDK errors for cross-language use
 *
 * This simplified error type uses protocol-compliant error codes from `ErrorCode`
 * in `cdk-common`, reducing duplication while providing structured error information
 * to FFI consumers.
 */
sealed class FfiException: kotlin.Exception() {
    
    /**
     * CDK error with protocol-compliant error code
     * The code corresponds to the Cashu protocol error codes (e.g., 11001, 20001, etc.)
     */
    class Cdk(
        
        /**
         * Error code from the Cashu protocol specification
         */
        val `code`: kotlin.UInt, 
        
        /**
         * Human-readable error message
         */
        val `errorMessage`: kotlin.String
        ) : FfiException() {
        override val message
            get() = "code=${ `code` }, errorMessage=${ `errorMessage` }"
    }
    
    /**
     * Internal/infrastructure error (no protocol error code)
     * Used for errors that don't map to Cashu protocol codes
     */
    class Internal(
        
        /**
         * Human-readable error message
         */
        val `errorMessage`: kotlin.String
        ) : FfiException() {
        override val message
            get() = "errorMessage=${ `errorMessage` }"
    }
    

    companion object ErrorHandler : UniffiRustCallStatusErrorHandler<FfiException> {
        override fun lift(error_buf: RustBuffer.ByValue): FfiException = FfiConverterTypeFfiError.lift(error_buf)
    }

    
}

/**
 * @suppress
 */
public object FfiConverterTypeFfiError : FfiConverterRustBuffer<FfiException> {
    override fun read(buf: ByteBuffer): FfiException {
        

        return when(buf.getInt()) {
            1 -> FfiException.Cdk(
                FfiConverterUInt.read(buf),
                FfiConverterString.read(buf),
                )
            2 -> FfiException.Internal(
                FfiConverterString.read(buf),
                )
            else -> throw RuntimeException("invalid error enum value, something is very wrong!!")
        }
    }

    override fun allocationSize(value: FfiException): ULong {
        return when(value) {
            is FfiException.Cdk -> (
                // Add the size for the Int that specifies the variant plus the size needed for all fields
                4UL
                + FfiConverterUInt.allocationSize(value.`code`)
                + FfiConverterString.allocationSize(value.`errorMessage`)
            )
            is FfiException.Internal -> (
                // Add the size for the Int that specifies the variant plus the size needed for all fields
                4UL
                + FfiConverterString.allocationSize(value.`errorMessage`)
            )
        }
    }

    override fun write(value: FfiException, buf: ByteBuffer) {
        when(value) {
            is FfiException.Cdk -> {
                buf.putInt(1)
                FfiConverterUInt.write(value.`code`, buf)
                FfiConverterString.write(value.`errorMessage`, buf)
                Unit
            }
            is FfiException.Internal -> {
                buf.putInt(2)
                FfiConverterString.write(value.`errorMessage`, buf)
                Unit
            }
        }.let { /* this makes the `when` an expression, which ensures it is exhaustive */ }
    }

}



